1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const COMPONENT_BLOCK_SIZE = 3;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	const INSURANCE_VALUES: Record<string, number> = {
16	  sword: 1000,
17	  amulet: 600,
18	  staff: 800,
19	  potion: 400,
20	};
21	
22	const COMPONENT_INSURANCE_VALUE = 250;
23	const DEDUCTIBLE = 100;
24	const CLAIM_ENCHANTMENT_THRESHOLD = 8;
25	const CLAIM_ENCHANTMENT_RATE = 0.5;
26	
27	const FIRST_INSURANCE_RATE = 0.1;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
31	const CURSED_SURCHARGE_RATE = 0.5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const HIGH_ENCHANTMENT_THRESHOLD = 5;
34	
35	const isStandardItem = (item: any): boolean => item.type in BASE_PREMIUMS;
36	
37	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
38	
39	const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type] ?? 0;
40	
41	function countByType(components: any[]): Record<string, number> {
42	  const counts: Record<string, number> = {};
43	  for (const c of components) {
44	    counts[c.type] = (counts[c.type] ?? 0) + 1;
45	  }
46	  return counts;
47	}
48	
49	function componentGroupPremium(count: number): number {
50	  return count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
51	}
52	
53	function componentPremium(items: any[]): number {
54	  const components = items.filter(isComponent);
55	  const typeCounts = countByType(components);
56	  return Object.values(typeCounts).reduce(
57	    (sum, count) => sum + componentGroupPremium(count),
58	    0,
59	  );
60	}
61	
62	function itemSurcharge(item: any): number {
63	  const base = itemBasePremium(item);
64	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
65	  const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
66	  return cursedSurcharge + enchantmentSurcharge;
67	}
68	
69	function validateItems(items: any[]): void {
70	  for (const item of items) {
71	    if (!isStandardItem(item) && !isComponent(item)) {
72	      throw new Error(`Unknown item type: ${item.type}`);
73	    }
74	  }
75	}
76	
77	function calculateQuotePremium(items: any[], customer: any, quoteIndex: number): number {
78	  validateItems(items);
79	  const standardItems = items.filter((item: any) => !isComponent(item));
80	  const standardBase = standardItems.reduce(
81	    (sum: number, item: any) => sum + itemBasePremium(item),
82	    0,
83	  );
84	  const standardSurcharges = standardItems.reduce(
85	    (sum: number, item: any) => sum + itemSurcharge(item),
86	    0,
87	  );
88	  const policyBase = standardBase + componentPremium(items);
89	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
90	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
91	  const followUpDiscount = quoteIndex > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
92	  return Math.ceil(policyBase + standardSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
93	}
94	
95	function itemInsuranceValue(item: any): number {
96	  if (isComponent(item)) return COMPONENT_INSURANCE_VALUE;
97	  return INSURANCE_VALUES[item.type] ?? 0;
98	}
99	
100	function insuranceSum(items: any[]): number {
101	  return items.reduce((sum: number, item: any) => sum + itemInsuranceValue(item), 0);
102	}
103	
104	function processClaim(step: any, policies: Map<number, any>): { payout: number; remainingCap: number } {
105	  const policy = policies.get(step.policy)!;
106	  const rawPayout = step.incident.damages.reduce(
107	    (sum: number, damage: any) => {
108	      const item = policy.items.find((i: any) => i.type === damage.itemType);
109	      const reimbursementRate = item?.enchantment >= CLAIM_ENCHANTMENT_THRESHOLD ? CLAIM_ENCHANTMENT_RATE : 1;
110	      return sum + Math.max(0, damage.amount * reimbursementRate - DEDUCTIBLE);
111	    },
112	    0,
113	  );
114	  const payout = Math.min(rawPayout, policy.remainingCap);
115	  policy.remainingCap -= payout;
116	  return { payout, remainingCap: policy.remainingCap };
117	}
118	
119	export function processScenario(scenario: any): { results: any[] } {
120	  let quoteCount = 0;
121	  const policies = new Map<number, any>();
122	  const results = scenario.steps.map((step: any, index: number) => {
123	    if (step.op === "claim") {
124	      return processClaim(step, policies);
125	    }
126	    const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount);
127	    policies.set(index, { items: step.items, remainingCap: insuranceSum(step.items) * 2 });
128	    quoteCount++;
129	    return { premium };
130	  });
131	  return { results };
132	}
